import json
import os
import boto3

s3 = boto3.client("s3")
dynamodb = boto3.resource("dynamodb")
sns = boto3.client("sns")
sqs = boto3.client("sqs")


def lambda_handler(event, context):
    action = event.get("action", "healthcheck")

    if action == "healthcheck":
        return response(200, {"status": "ok", "service": os.getenv("AWS_LAMBDA_FUNCTION_NAME")})

    if action == "s3_list":
        bucket = os.environ["BUCKET_NAME"]
        result = s3.list_objects_v2(Bucket=bucket, MaxKeys=10)
        return response(200, {"bucket": bucket, "objects": result.get("Contents", [])})

    if action == "dynamodb_get":
        table_name = os.environ["DDB_TABLE_NAME"]
        key = event["key"]
        table = dynamodb.Table(table_name)
        item = table.get_item(Key=key).get("Item")
        return response(200, {"item": item})

    if action == "sns_publish":
        topic_arn = os.environ["SNS_TOPIC_ARN"]
        message = event.get("message", "Hello from Lambda")
        result = sns.publish(TopicArn=topic_arn, Message=message)
        return response(200, {"message_id": result["MessageId"]})

    if action == "sqs_send":
        queue_url = os.environ["SQS_QUEUE_URL"]
        message = event.get("message", "Hello from Lambda")
        result = sqs.send_message(QueueUrl=queue_url, MessageBody=json.dumps({"message": message}))
        return response(200, {"message_id": result["MessageId"]})

    return response(400, {"error": f"Unsupported action: {action}"})


def response(status_code, body):
    return {
        "statusCode": status_code,
        "headers": {"Content-Type": "application/json"},
        "body": json.dumps(body, default=str),
    }